result = []

def genera():
    for m in memo:
        inizio = genera_timestamp_casuale()
        if m[3] == "TRUE":
            minuti = random.randint(1,7) * 1440
            fine = genera_timestamp_aggiunto(inizio, minuti)
            result.append( (m[0], m[1], time.strftime("%Y-%m-%d %H:%M:%S", time.localtime(inizio)), time.strftime("%Y-%m-%d %H:%M:%S", time.localtime(fine))) )
        else: 
            fine = "NULL"
            result.append( (m[0], m[1], time.strftime("%Y-%m-%d %H:%M:%S", time.localtime(inizio)), fine) )


def stampa():
    print("memorizzazioni:")
    n = 0
    for server, versione, inizio, fine in result:
        n = n+1
        print(f'({server}, {versione}, "{inizio}", "{fine}"),', end="")
        if(n % 50 == 0):
            print(" ")
    print(" ")

def genera_timestamp_casuale():
    inizio_timestamp = time.mktime((2023, 1, 1, 0, 0, 0, 0, 0, 0)) 
    fine_timestamp = time.mktime((2024, 2, 1, 0, 0, 0, 0, 0, 0))  
    timestamp_casuale = random.randint(inizio_timestamp, fine_timestamp)
    return timestamp_casuale

def genera_timestamp_aggiunto(timestamp, minuti):
    secondi_aggiunti = minuti * 60  
    nuovo_timestamp = timestamp + secondi_aggiunti
    return nuovo_timestamp

if __name__ == "__main__":
    genera()
    stampa()